import{_ as a,o as t,c as o,a5 as i}from"./chunks/framework.BXfsq1AV.js";const u=JSON.parse('{"title":"Search Dialog","description":"","frontmatter":{},"headers":[],"relativePath":"guide/search-dialog.md","filePath":"guide/search-dialog.md"}'),r={name:"guide/search-dialog.md"};function s(c,e,n,l,h,d){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="search-dialog" tabindex="-1">Search Dialog <a class="header-anchor" href="#search-dialog" aria-label="Permalink to “Search Dialog”">​</a></h1><p>The Search Dialog is the command center of Milki Launcher. It is where you search for apps, files, contacts, execute custom actions, and get smart suggestions—all from a single input.</p><h2 id="the-omnibar-should-you-call-it-search-dialog-or-omnibar" tabindex="-1">The Omnibar(should you call it search dialog or omnibar?) <a class="header-anchor" href="#the-omnibar-should-you-call-it-search-dialog-or-omnibar" aria-label="Permalink to “The Omnibar(should you call it search dialog or omnibar?)”">​</a></h2><p>The core of Milki is the Omnibar—a central search input that handles almost everything.</p><ul><li><strong>App Search:</strong> Type part of an app name or even its initials to instantly launch it.</li><li><strong>Web Search:</strong> Directly search the web using your preferred search engine.</li><li><strong>Quick Actions:</strong> Execute built-in commands directly from the search bar (e.g., <code>/settings</code>, <code>/wifi</code>).</li></ul><h2 id="recent-apps" tabindex="-1">Recent Apps <a class="header-anchor" href="#recent-apps" aria-label="Permalink to “Recent Apps”">​</a></h2><p>When you open the Search Dialog, it immediately shows your recently accessed apps for quick return.</p><ul><li>Pressing Enter opens the latest app</li><li>Recent apps are those opened from the drawer or search dialog. Apps launched from home screen icons are not added to recent apps since they are already one tap away.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: Screenshot</p><p>Add a screenshot of the Search Dialog opening with recently accessed apps displayed at the top.</p></div><h2 id="clipboard-actions" tabindex="-1">Clipboard Actions <a class="header-anchor" href="#clipboard-actions" aria-label="Permalink to “Clipboard Actions”">​</a></h2><p>Milki automatically detects content on your clipboard and surfaces relevant suggested actions the moment you open the dialog.</p><ul><li><strong>Web Search:</strong> If it looks like a query, search the web directly.</li><li><strong>Open in App:</strong> If it is a link to YouTube, Instagram, or another service, open it in the corresponding installed app.</li><li><strong>Custom Actions:</strong> You can define your own clipboard action rules in <code>Settings</code>.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: GIF</p><p>Show a GIF of copying a YouTube URL, opening the Search Dialog, and tapping the &quot;Open in YouTube&quot; suggestion.</p></div><h2 id="searching-for-apps" tabindex="-1">Searching for Apps <a class="header-anchor" href="#searching-for-apps" aria-label="Permalink to “Searching for Apps”">​</a></h2><p>Start typing with no prefix and Milki will search your installed apps. Partial matches and initials both work.</p><h2 id="url-detection" tabindex="-1">URL Detection <a class="header-anchor" href="#url-detection" aria-label="Permalink to “URL Detection”">​</a></h2><p>When you type or paste a URL into the search input, Milki detects it and gives you options:</p><ul><li><strong>Open in Default Browser</strong></li><li><strong>Open in an Installed App</strong> that can handle that URL scheme</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: GIF</p><p>Show a GIF of typing a URL into the search bar and a prompt appearing to choose between browser and a specific app.</p></div><h2 id="system-prefixes" tabindex="-1">System Prefixes <a class="header-anchor" href="#system-prefixes" aria-label="Permalink to “System Prefixes”">​</a></h2><p>Prefixes let you narrow your search scope or trigger custom actions. Milki ships with two built-in prefixes:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Scope</th><th>Description</th></tr></thead><tbody><tr><td><code>f</code></td><td>Files</td><td>Shows your recent files and lets you search all files on your device</td></tr><tr><td><code>c</code></td><td>Contacts</td><td>Shows your recent contacts and lets you search all contacts. You can call someone directly from the results</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: Screenshot</p><p>Add a screenshot showing a <code>c</code> prefix search with recent contacts at the top and a visible &quot;Call&quot; action button.</p></div><h2 id="drag-to-home-screen" tabindex="-1">Drag to Home Screen <a class="header-anchor" href="#drag-to-home-screen" aria-label="Permalink to “Drag to Home Screen”">​</a></h2><p>Any item from the Search Dialog—app, file, or contact—can be dragged directly onto your home screen for quick access.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: GIF</p><p>Show a GIF of searching for an app in the Search Dialog, long-pressing the result, and dragging it onto an empty home screen cell.</p></div><h2 id="multiple-prefixes-for-the-same-target" tabindex="-1">Multiple Prefixes for the Same Target <a class="header-anchor" href="#multiple-prefixes-for-the-same-target" aria-label="Permalink to “Multiple Prefixes for the Same Target”">​</a></h2><p>You can map more than one prefix to the same search target or URL. This is especially useful for bilingual users.</p><p>For example, if you use both English and Arabic, you can create two prefixes that both search Wikipedia—one triggered by <code>w</code> (for English) and another by <code>و</code> (for Arabic). This way you can switch languages naturally without changing any settings mid-search.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: Screenshot</p><p>Add a screenshot of the Settings &gt; Prefixes screen showing two prefixes pointing to the same service but different language endpoints.</p></div><h2 id="custom-prefixes" tabindex="-1">Custom Prefixes <a class="header-anchor" href="#custom-prefixes" aria-label="Permalink to “Custom Prefixes”">​</a></h2><p>You can create your own prefixes for anything you want to search. Examples:</p><ul><li>Search Wikipedia (<code>w</code>)</li><li>Search an image engine (<code>i</code>)</li><li>Search a specific website or API</li></ul><p>Add and manage custom prefixes in <code>Settings &gt; Prefixes</code>. Each prefix maps to a search URL or handler of your choice.</p><h2 id="color-coded-prefixes" tabindex="-1">Color-Coded Prefixes <a class="header-anchor" href="#color-coded-prefixes" aria-label="Permalink to “Color-Coded Prefixes”">​</a></h2><p>Every prefix can be assigned a unique color. When you type a prefix into the search dialog, the entire input bar shifts to that prefix&#39;s color. This gives you instant visual feedback about which search scope you are in.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: Screenshot</p><p>Add a screenshot showing the search dialog with different prefix colors active side by side, each with a distinct tinted input bar.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: Screenshot</p><p>Add a screenshot of the Settings &gt; Prefixes screen showing the color picker next to each prefix.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">Placeholder: Screenshot</p><p>Add a screenshot of the Settings &gt; Prefixes screen showing existing prefixes and an &quot;Add New Prefix&quot; form.</p></div>',39)])])}const g=a(r,[["render",s]]);export{u as __pageData,g as default};
